    return [torch.rand([4, 4, 4, 4]), torch.rand([4, 4, 4, 4])]


def get_init_inputs():
    return [[], {'in_kernels_1': 4, 'in_kernels_2': 4, 'kernels': 4}]

import torch
import torch.nn as nn


class HLoss(nn.Module):

    def __init__(self):
        super(HLoss, self).__init__()

    def forward(self, x):
        b = torch.exp(x) * x
        b = -1.0 * b.sum(dim=1)
        return b


